import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Limiting the buffer size to prevent buffer overflow
        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        // Copy characters from input to buffer, ensuring not to exceed buffer size
        for (int i = 0; i < input.length() && i < bufferSize; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Secure buffer handling: " + String.valueOf(buffer));
    }
}

